// Solution
var solve = function(routes) {
    var correctedRoutes = [];
    for (var i = 0; i < routes.length; i++) {
        var route = routes[i];
        if (route.includes('/:')) {
            correctedRoutes.push(route);
        } else {
            correctedRoutes.unshift(route);
        }
    }
    return correctedRoutes;
};
// Call the function with the routes array
var routes = ['/users', '/posts/:id/comments', '/users/:id'];
var correctedRoutes = solve(routes);
console.log(correctedRoutes);
